import sys

def solve():
    input = sys.stdin.read().split()
    ptr = 0
    t = int(input[ptr])
    ptr += 1
    for _ in range(t):
        n = int(input[ptr])
        ptr += 1
        a = list(map(int, input[ptr:ptr + n]))
        ptr += n

        sorted_a = sorted(a)
        if a == sorted_a:
            print("YES")
            continue

        # Check if there's any duplicate element
        has_duplicate = False
        for i in range(n - 1):
            if sorted_a[i] == sorted_a[i + 1]:
                has_duplicate = True
                break

        if has_duplicate:
            print("YES")
        else:
            # Check parity of permutation
            pos_map = {val: idx for idx, val in enumerate(sorted_a)}
            visited = [False] * n
            inversion_count = 0
            for i in range(n):
                if not visited[i]:
                    cycle_length = 0
                    j = i
                    while not visited[j]:
                        visited[j] = True
                        j = pos_map[a[j]]
                        cycle_length += 1
                    inversion_count += (cycle_length - 1)
            if inversion_count % 2 == 0:
                print("YES")
            else:
                print("NO")

solve()

